package core.org.apache.calcite.rel.logical;

public class LogicalSortExchange extends SortExchange { private LogicalSortExchange ( RelOptCluster cluster , RelTraitSet traitSet , RelNode input , RelDistribution distribution , RelCollation collation ) { super ( cluster , traitSet , input , distribution , collation ) ; } public static LogicalSortExchange create ( RelNode input , RelDistribution distribution , RelCollation collation ) { RelOptCluster cluster = input . getCluster ( ) ; collation = RelCollationTraitDef . INSTANCE . canonize ( collation ) ; distribution = RelDistributionTraitDef . INSTANCE . canonize ( distribution ) ; RelTraitSet traitSet = input . getTraitSet ( ) . replace ( Convention . NONE ) . replace ( distribution ) . replace ( collation ) ; return new LogicalSortExchange ( cluster , traitSet , input , distribution , collation ) ; } @ Override public SortExchange copy ( RelTraitSet traitSet , RelNode newInput , RelDistribution newDistribution , RelCollation newCollation ) { return new LogicalSortExchange ( this . getCluster ( ) , traitSet , newInput , newDistribution , newCollation ) ; } }